from typing import List, Dict, Any

class Iterators:

    class BooksSequence:

        def __init__(self, books_data: List[Dict[str, Any]]):
            self.__books_data: List[Dict[str, Any]] = books_data #JSON with messy data of books

        def __iter__(self):
            self.ind: int = -1 #ghost startting point
            return self

        def __next__(self) -> str | None:
            self.ind += 1

            if len(self.__books_data) <= self.ind:
                raise StopIteration #It will get us out of the loop when the reading is finished

            if 'volumeInfo' not in self.__books_data[self.ind]:
                return None #Return None for broken field

            self.vol_info: Dict[str, Any] = self.__books_data[self.ind]['volumeInfo']

            if 'title' not in self.vol_info or 'authors' not in self.vol_info:
                return None #Return None for broken field

            self.title: str = self.vol_info['title']
            self.author: str = self.vol_info['authors'][0] #Get the first author
            self.filtered_info: str = "@".join([self.author, self.title]) #String in the format author@title
            return self.filtered_info #Returning clean data as string
        
    class GamesSequence:

        def __init__(self, games_json: List[Dict[str, Any]]):
            self.__games_json: List[Dict[str, Any]] = games_json
        
        def __iter__(self):
            self.ind: int = -1 #Setting the ghost index of the sequence.
            return self

        def __next__(self) -> str | None:
            self.ind += 1

            if self.ind >= len(self.__games_json):
                raise StopIteration #Closes the 'for' loop if we can't extract nothing else from the list of games.

            self.__game: Dict[str, int | str] = self.__games_json[self.ind]#Selecting a game
            
            if 'name' not in self.__game:
                return None #Return None if the JSON hasn't 'name' attribute for this field
            
            return self.__game['name'] #Returns the title

